INSERT INTO `action_run_job` VALUES (1,1,1,1,'bbbc8dd8fe948e8982f4a28b4c91c854709fd6b0',0,'Deploy to EC2 pulsefocus',0,_binary 'name: Deploy-pulsefocus-app\n\"on\":\n    push:\n        branches:\n            - master\njobs:\n    deploy:\n        name: Deploy to EC2 pulsefocus\n        runs-on: ubuntu-latest\n        env:\n            DEPLOY_PATH: ${{ secrets.EC2_DEPLOY_PATH }}\n        steps:\n            - name: Checkout the files\n              uses: actions/checkout@v3\n            - name: Copy project files to EC2\n              uses: easingthemes/ssh-deploy@main\n              env:\n                SSH_PRIVATE_KEY: ${{ secrets.EC2_SSH_PULSEFOCUS_KEY }}\n                ARGS: \'-rltgoDzvO --delete\'\n                SOURCE: \'./\'\n                REMOTE_HOST: ec2-3-233-229-119.compute-1.amazonaws.com\n                REMOTE_USER: admin\n                TARGET: ${{ env.DEPLOY_PATH }}\n                EXCLUDE: \'/.git/, /.gitea/, /node_modules/, /.env, /.env.*, /README.md\'\n            - name: Rebuild and restart containers on EC2\n              uses: appleboy/ssh-action@v1.0.3\n              with:\n                host: ec2-3-233-229-119.compute-1.amazonaws.com\n                key: ${{ secrets.EC2_SSH888_PULSEFOCUS_KEY }}\n                script: |-\n                    set -e\n                    cd \"${{ env.DEPLOY_PATH }}\"\n                    docker compose pull || true\n                    docker compose up -d --build --remove-orphans\n                username: admin\n','deploy','null','[\"ubuntu-latest\"]',0,3,0,1775254952,1775253854,1775254952),(2,2,1,1,'fb2319ea752ece7069671ab73718838d85a344da',0,'Deploy to EC2 pulsefocus',3,_binary 'name: Deploy-pulsefocus-app\n\"on\":\n    push:\n        branches:\n            - master\njobs:\n    deploy:\n        name: Deploy to EC2 pulsefocus\n        runs-on: ubuntu-latest\n        env:\n            DEPLOY_PATH: ${{ secrets.EC2_DEPLOY_PATH }}\n        steps:\n            - name: Checkout the files\n              