f .env.example ] && cp .env.example .env\n                    docker compose up -d --build --remove-orphans\n                username: admin\n','deploy','null','[\"ubuntu-latest\"]',44,1,1775344476,1775344504,1775344474,1775344505),(40,40,1,1,'3070e0f7e16c086bd229829edf2e86271bbed787',0,'Unit Tests',1,_binary 'name: Continuous Integration\n\"on\":\n    push:\n        branches: [master]\n    pull_request:\n        branches: [master]\njobs:\n    unit_tests:\n        name: Unit Tests\n        runs-on: ubuntu-latest\n        steps:\n            - name: Checkout\n              uses: actions/checkout@v4\n            - name: Create .env\n              run: cp .env.example .env\n            - name: Composer install\n              run: bash ./run.sh composer install --no-interaction --prefer-dist --no-progress\n            - name: Up containers\n              run: bash ./run.sh up -d\n            - name: Run PHPUnit\n              run: bash ./run.sh test\n            - if: always()\n              name: Down containers\n              run: bash ./run.sh down -v\n','unit_tests','null','[\"ubuntu-latest\"]',45,2,1775344505,1775344508,1775344475,1775344509),(41,41,1,1,'009737510f4d38b68738c96be64c65d3fbbb3619',0,'deploy',1,_binary 'name: Deploy-pulsefocus-app\n\"on\":\n    push:\n        branches: [master]\njobs:\n    deploy:\n        name: deploy\n        runs-on: ubuntu-latest\n        steps:\n            - name: Checkout\n              uses: actions/checkout@v3\n            - name: Prepare files\n              run: |\n                # Lista arquivos para debug\n                echo \"Arquivos na raiz:\" && ls -la\n\n                mkdir -p .deploy-temp\n\n                # Copia tudo vis├Łvel (incluindo novos arquivos)\n                cp -r * .deploy-temp/ 2>/dev/null || true\n\n                # Copia dotfiles espec├Łficos\n                cp .env.example .gitignore .deploy-temp/ 2>/dev/null || true\n\n                # Cria tarball SEM o prefixo .deploy-temp (extrai diret