p\n\n                # Copia tudo vis├Łvel (incluindo novos arquivos)\n                cp -r * .deploy-temp/ 2>/dev/null || true\n\n                # Copia dotfiles espec├Łficos\n                cp .env.example .gitignore .deploy-temp/ 2>/dev/null || true\n\n                # Cria tarball SEM o prefixo .deploy-temp (extrai direto na raiz)\n                cd .deploy-temp && tar -czf ../deploy.tar.gz . && cd ..\n\n                echo \"Conte├║do do tarball:\" && tar -tzf deploy.tar.gz\n            - name: Copy archive to EC2\n              uses: appleboy/scp-action@v0.1.7\n              with:\n                host: ec2-3-233-229-119.compute-1.amazonaws.com\n                key: ${{ secrets.EC2_SSH_PULSEFOCUS_KEY }}\n                source: deploy.tar.gz\n                target: /home/admin/pulsefocus-app\n                username: admin\n            - name: Extract and restart\n              uses: appleboy/ssh-action@v1.0.3\n              with:\n                host: ec2-3-233-229-119.compute-1.amazonaws.com\n                key: ${{ secrets.EC2_SSH_PULSEFOCUS_KEY }}\n                script: |\n                    # Evita deploy concorrente no mesmo host.\n                    LOCK_FILE=/tmp/pulsefocus-deploy.lock\n                    exec 9>\"$LOCK_FILE\"\n                    flock -w 900 9 || { echo \"Outro deploy ainda em execu├¦├Żo (timeout de lock).\"; exit 1; }\n\n                    cd /home/admin/pulsefocus-app\n\n                    # Debug: mostra o que tem antes\n                    echo \"Antes:\" && ls -la\n\n                    # Remove arquivos antigos (exceto volumes do docker) e extrai\n                    # CUIDADO: ajuste o rm -rf conforme sua estrutura\n                    find . -maxdepth 1 -type f ! -name \"deploy.tar.gz\" ! -name \"*.sql\" ! -name \".env\" -delete 2>/dev/null || true\n                    find . -maxdepth 1 -type d ! -name \".\" ! -name \"volumes\" ! -name \"data\" -exec rm -rf {} + 2>/dev/null || true\n\n                    # Extrai for├¦ando sobrescrita\n                    tar -xzf deploy.tar.gz --overwrite --no-same-owner --no-same-permissions\n\n                    echo \"Depois:\" && ls -la\n\n                    rm deploy.tar.gz\n\n                    # Recria .env se necess├Īrio (copia do .env.example se n├Żo existir)\n                    if [ ! -f .env ] && [ -f .env.example ]; then\n                      cp .env.example .env\n                    fi\n\n                    export COMPOSE_PARALLEL_LIMIT=1\n\n                    max_attempts=6\n                    delay=5\n                    attempt=1\n\n                    while [ \"$attempt\" -le \"$max_attempts\" ]; do\n                      set +e\n                      compose_output=$(docker compose up -d --build --remove-orphans 2>&1)\n                      compose_status=$?\n                      set -e\n\n                      echo \"$compose_output\"\n\n                      if [ \"$compose_status\" -eq 0 ]; then\n                        echo \"Deploy concluido com sucesso.\"\n                        break\n                      fi\n\n                      if echo \"$compose_output\" | grep -qi \"removal of container .* is already in progress\"; then\n                        if [ \"$attempt\" -eq \"$max_attempts\" ]; then\n                          echo \"Docker continuou em remocao de container apos ${max_attempts} tentativas.\"\n                          exit 1\n                        fi\n\n                        echo \"Docker ainda removendo container. Nova tentativa em ${delay}s (tentativa ${attempt}/${max_attempts}).\"\n                        sleep \"$delay\"\n                        delay=$((delay * 2))\n                        if [ \"$delay\" -gt 60 ]; then\n                          delay=60\n                        fi\n                        attempt=$((attempt + 1))\n                        continue\n                      fi\n\n                      echo \"Falha no docker compose por motivo diferente de remocao em progresso.\"\n                      exit \"$compose_status\"\n                    done\n                username: admin\n','deploy','null','[\"ubuntu-latest\"]',68,1,1775346436,1775346464,1775346435,1775346464),(64,64,1,1,'a4629a2afc7dcb48bcbd6b331789c92b90587588',0,'Tests',1,_binary 'name: Continuous Integration\n\"on\":\n    push:\n        branches: [master]\n    pull_request:\n        branches: [master]\njobs:\n    tests:\n        name: Tests\n        runs-on: ubuntu-latest\n        steps:\n            - name: Checkout\n              uses: actions/checkout@v4\n            - name: Setup PHP\n              uses: shivammathur/setup-php@v2\n              with:\n                coverage: none\n                extensions: dom, mbstring, xml, xmlwriter, json, tokenizer\n                php-version: \"8.2\"\n                tools: composer:v2\n            - name: Create .env\n              run: cp .env.example .env\n            - name: Composer install\n              run: composer install --no-interaction --prefer-dist --no-progress\n            - name: Run PHPUnit\n              run: ./vendor/bin/phpunit --colors=always tests\n','tests','null','[\"ubuntu-latest\"]',69,3,1775346464,1775346482,1775346435,1775346482),(65,65,1,1,'fef87625db78e0dba654c6a010fde4edb0d6a27e',0,'deploy',1,_binary 'name: Deploy-pulsefocus-app\n\"on\":\n    push:\n        branches: [master]\njobs:\n    deploy:\n        name: deploy\n        runs-on: ubuntu-latest\n        steps:\n            - name: Checkout\n              uses: actions/checkout@v3\n            - name: Prepare files\n              run: |\n                # Lista  para debug\n                echo \"Arquivos na raiz:\" && ls -la\n\n                mkdir -p .deploy-temp\n\n                # Copia tudo vis├Łvel (incluindo novos arquivos)\n                cp -r * .deploy-temp/ 2>/dev/null || true\n\n                # Copia dotfiles espec├Łficos\n                cp .env.example .gitignore .deploy-temp/ 2>/dev/null || true\n\n      