deploy','null','[\"ubuntu-latest\"]',70,1,1775346484,1775346511,1775346482,1775346512),(66,66,1,1,'fef87625db78e0dba654c6a010fde4edb0d6a27e',0,'Tests',1,_binary 'name: Continuous Integration\n\"on\":\n    push:\n        branches: [master]\n    pull_request:\n        branches: [master]\njobs:\n    tests:\n        name: Tests\n        runs-on: ubuntu-latest\n        steps:\n            - name: Checkout\n              uses: actions/checkout@v4\n            - name: Setup PHP\n              uses: shivammathur/setup-php@v2\n              with:\n                coverage: none\n                extensions: dom, mbstring, xml, xmlwriter, json, tokenizer\n                php-version: \"8.2\"\n                tools: composer:v2\n            - name: Create .env\n              run: cp .env.example .env\n            - name: Composer install\n              run: composer install --no-interaction --prefer-dist --no-progress\n            - name: Run PHPUnit\n              run: ./vendor/bin/phpunit --colors=always tests\n','tests','null','[\"ubuntu-latest\"]',71,1,1775346512,1775346552,1775346482,1775346552);
